#!/usr/bin/perl
use strict;
use CGI qw(:standard);

my $q = new CGI;
my $redirect_url = $q->param('next');

if (defined($redirect_url)) {
    print "Location: $redirect_url\n\n";
} else {
    print header(), start_html("Error"), h1("No next parameter provided."), end_html;
}